import React from 'react'; // 'React' should start with a capital letter
import { Responsive, WidthProvider } from "react-grid-layout";

const ResponsiveGridLayout = WidthProvider(Responsive);

export default class MyGrid3 extends React.Component {
  render() {
    // 각 브레이크포인트에 대한 레이아웃 정의
    const layouts = {
      lg: [
        { i: "a", x: 0, y: 0, w: 1, h: 2, static: true },
        // minW가 w보다 작거나 같도록 조정
        { i: "b", x: 1, y: 0, w: 2, h: 2, minW: 2, maxW: 4 }, 
        { i: "c", x: 2, y: 0, w: 1, h: 2 }
      ],
      md: [
        { i: "a", x: 0, y: 0, w: 1, h: 2, static: true },
        { i: "b", x: 1, y: 0, w: 2, h: 2 }, // 여기도 w 와 minW를 일치시킴
        { i: "c", x: 2, y: 0, w: 1, h: 2 }
      ],
      // 필요에 따라 sm, xs, xxs 정의
    };
    
    return (
      <ResponsiveGridLayout
        className="layout"
        layouts={layouts}
        breakpoints={{ lg: 1200, md: 996, sm: 768, xs: 480, xxs: 0 }}
        cols={{ lg: 12, md: 10, sm: 6, xs: 4, xxs: 2 }}
      >
        <div key="a">1111</div>
        <div key="b">2222</div>
        <div key="c">3333</div>
      </ResponsiveGridLayout>
    );
  }
}
