// 이건 react 프로젝트다
import react from 'react'
import { Outlet } from 'react-router-dom'
import styled from 'styled-components'

//import { createEffect, createMemo, createSignal } from 'solid-js'
//import { Routes, Route, Link, Router } from 'solid-app-router'  // npm install solid-app-router --save
//import { styled } from 'solid-styled-components'  // npm install solid-styled-components --save

export default function Main(_props) {
  // react.useState 는 solid-js 에서 createSignal 로 대체된다.
  //const [bSign, setSign] = react.useState(false)
  // react.useEffect 는 solid-js 에서 createEffect 로 대체된다.
  react.useEffect(() => {
    console.log('Main 시작')
    return () => {
        console.log('Main 소멸')
    }
  })
  return (
    <Base>
    <h4>메인 페이지</h4>
      <Outlet />
    </Base>
  )
}
// stackoverflow 처럼 상단과 하단 고정되어 있는 Header 와 Footer 를 만들어 보자.
// stackoverflow 는 <header className="s-topbar ps-fixed t0 l0 js-top-bar"> <div className="s-topbar--container"> 이렇게 되어 있다.
// solid-styled-components 를 사용하면, styled.div 로 감싸서 사용할 수 있다.
// react 는 styled.div, solid-js 는 styled('div')
// position 의 기본값은 static 이다.
// position 에는 static, relative, absolute, fixed, sticky 가 있다.
//const Base = styled('div')`
const Base = styled.div`
  position: fixed;
  top: 3.4vh;
  min-height: 92vh;
  left: 0;
  width: 100%;
  background-color: rgba(0, 0, 0, 0.7);
  color: #fff;
  padding: 0;
`
  
