import styled from 'styled-components'
//import { styled } from 'solid-styled-components'  // npm install solid-styled-components --save
//import { Routes, Route, Router, Navigate } from 'solid-app-router'

import styles from '../../css/App.module.css'

const clicked_goto_site = () => {
  window.open('https://github.com/dwerasd', '_blank')
}

export default function Footer() {
    return (
      <Base>
        <MenuLeft>

        </MenuLeft>
  
        <MenuRight>
          <MenuLink className={styles.menulink} onClick={clicked_goto_site}>Github</MenuLink>
        </MenuRight>
      </Base>
    )
}

const Base = styled.div`
  display: flex;
  flex-direction: row;
  min-height: 5vh;
  justify-content: flex-start;
  align-items: center;
  width: 100%;
  height: 100%;
  margin-left: 0;
  margin-right: 0;
  padding: 0 20px;
  box-sizing: border-box;
  background-color: #282c34;
  color: white;
`
//const MenuLeft = styled('div')`
const MenuLeft = styled.div`
  display: flex;
  flex-direction: row;
  justify-content: flex-start;
  align-items: center;
  width: 100%;
  height: 100%;
`
//const MenuRight = styled('div')`
const MenuRight = styled.div`
  display: flex;
  flex-direction: row;
  justify-content: flex-end;
  align-items: center;
  width: 100%;
  height: 100%;
`
//const MenuLink = styled(MenuItem)`
const MenuLink = styled.div`
  display: flex;
  flex-direction: row;
  align-items: center;
  height: 100%;
  padding: 0 10px;
  box-sizing: border-box;
  cursor: pointer;
  font-size: 2.0rem;
  font-weight: bold;
  color: #fff;
  text-align: left;

  font-size: 1.0rem;
  padding: 0 10px;
  color: #fff;
  text-decoration: none;
  cursor: pointer;
  &:hover {
    color: #3fa0b3;
  }
`
