import React, { useState } from 'react';
import { Outlet, useLocation } from 'react-router-dom'
import styled from 'styled-components'

//import './testcalc.css';

const TestCalc = () => {
  const [state, setState] = useState({
    purchasePrice: 0,
    currentShares: 0,
    currentPrice: 0,
    additionalPurchaseAmount: 0,
    plannedPurchaseShares: 0,
    commission: 0.23,
    plannedSalePrice: 0,
    scrollValue: 0,
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    const parsedValue = parseFloat(value) || 0;
    setState(prevState => ({
      ...prevState,
      [name]: parsedValue,
    }));

    if (name === 'additionalPurchaseAmount') {  // 추가 매수 금액
      const calculatedShares = value ? parsedValue / state.currentPrice : 0;
      setState(prevState => ({
        ...prevState,
        plannedPurchaseShares: calculatedShares,
      }));
    } else if (name === 'plannedPurchaseShares') {  // 추가 매수 주식 수량 텍스트박스
      const calculatedAmount = value ? parsedValue * state.currentPrice : 0;
      setState(prevState => ({
        ...prevState,
        additionalPurchaseAmount: calculatedAmount,
        scrollValue: parsedValue,
      }));
    } else if (name === 'scrollValue') {  // 추가 매수 주식 수량 (스크롤바)
      const calculatedShares = parsedValue;
      setState(prevState => ({
        ...prevState,
        //plannedPurchaseShares: parseFloat(value),
        plannedPurchaseShares: calculatedShares,
        additionalPurchaseAmount: calculatedShares * state.currentPrice,
      }));
    }
  };

  const calculateResults = () => {
    const totalShares = state.currentShares + state.plannedPurchaseShares;
    //const totalShares = state.currentShares + state.scrollValue
    console.log('totalShares:', totalShares);
    const totalCost = (state.purchasePrice * state.currentShares) + state.additionalPurchaseAmount + state.commission;
    const adjustedAveragePrice = totalCost / totalShares;
    const saleRevenue = state.plannedSalePrice * state.plannedPurchaseShares;
    const netProfit = saleRevenue - (state.plannedPurchaseShares * adjustedAveragePrice) - state.commission;

    return {
      saleRevenue,
      adjustedAveragePrice,
      netProfit,
    };
  };

  const { saleRevenue, adjustedAveragePrice, netProfit } = calculateResults();

  return (
    <Base>
      <h1>평단 계산기</h1>
      <div className="form">
        <div className="input-group">
          <label>수수료:</label>
          <input type="number" name="commission" value={state.commission} onChange={handleChange} placeholder="수수료" />
        </div>
        <div className="input-group">
          <label>현재 평균단가:</label>
          <input type="number" name="purchasePrice" value={state.purchasePrice} onChange={handleChange} placeholder="구매 가격" />
          <label> - 매수가격</label>
        </div>
        <div className="input-group">
          <label>보유 주식 수:</label>
          <input type="number" name="currentShares" value={state.currentShares} onChange={handleChange} placeholder="보유 주식 수" />
          <label> - 물린 주식수</label>
        </div>
        <br/>
        <div className="input-group">
          <label>현재 가격:</label>
          <input type="number" name="currentPrice" value={state.currentPrice} onChange={handleChange} placeholder="현재 가격" />
          <label> - 해당 종목 현재가</label>
        </div>
        <br/>
        <div className="input-group">
          <label>추가 매수 수량:</label>
          <input type="number" name="plannedPurchaseShares" value={state.plannedPurchaseShares.toFixed(0)} onChange={handleChange} placeholder="구매 예정 주식 수량" />
          <input type="range" name="scrollValue" min="1" max="10000" value={state.scrollValue} onChange={handleChange} style={{ width: '500px' }} />
          <br/>
          <span style={{ backgroundColor: 'yellow', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
          {state.scrollValue}
          </span>
          <span> 주를 추가 매수 한다면 총 주식수는</span>
          <span style={{ backgroundColor: 'yellow', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
           {state.currentShares + state.scrollValue}
          </span>
          <span>
            개, 평균단가는
            <span style={{ backgroundColor: 'yellow', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
             {adjustedAveragePrice.toFixed(0)}
             </span>
              원이 됩니다.</span>
        </div>
        <br/>
        <div className="input-group">
          <label>추가 매수 추정 금액:</label>
          <input type="number" name="additionalPurchaseAmount" value={state.additionalPurchaseAmount} onChange={handleChange} placeholder="추가 매수 예정 금액" />
          <br/>
          <span style={{ backgroundColor: 'pink', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
          {state.currentPrice}
          </span>   
              원에 
          <span style={{ backgroundColor: 'yellow', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
            {state.scrollValue}
          </span>
          <span> 주를 추가 매수 하려면 </span>

          <span style={{ backgroundColor: 'lightgreen', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
           {state.additionalPurchaseAmount}
           </span>
            원이 필요합니다.
           
        </div>
        

        <div className="input-group">
          <label>판매 예정 가격:</label>
          <input type="number" name="plannedSalePrice" value={state.plannedSalePrice} onChange={handleChange} placeholder="판매 예정 가격" />
        </div>

        <div>예상 매도 정산 금액: {saleRevenue}</div>
        
        <div>순수익: {netProfit}</div>
      </div>
      <Outlet />
    </Base>
  );
};

export default TestCalc;

// stackoverflow 처럼 상단과 하단 고정되어 있는 Header 와 Footer 를 만들어 보자.
