import react from "react"
import { Link, useLocation } from 'react-router-dom'

import styled from 'styled-components'
import styles from '../../css/App.module.css'

export default function Header(_props){
  const currentLocation = useLocation()
  react.useEffect(() => {
    console.log("Header 컴포넌트 나타남", currentLocation.pathname)
    
    return () => {
      console.log("Header cleanUp 함수")
    }
  }, [currentLocation.pathname])
  
  //const isAdmin = currentLocation.pathname.includes('/admin')
  return (
    <Base>
      <MenuLeft>
        <HomeLink><Link to='/' className={styles.homelink}>HOME</Link></HomeLink>
        <MenuLink><Link to='/test/grid1' className={currentLocation.pathname === '/test/grid1' ? styles.active : styles.menulink}>그리드1</Link></MenuLink>
        <MenuLink><Link to='/test/grid2' className={currentLocation.pathname === '/test/grid2' ? styles.active : styles.menulink}>그리드2</Link></MenuLink>
        <MenuLink><Link to='/test/grid3' className={currentLocation.pathname === '/test/grid3' ? styles.active : styles.menulink}>그리드3</Link></MenuLink>
        <MenuLink><Link to='/test/grid4' className={currentLocation.pathname === '/test/grid4' ? styles.active : styles.menulink}>그리드4</Link></MenuLink>
        <MenuLink><Link to='/testcalc' className={currentLocation.pathname === '/testcalc' ? styles.active : styles.menulink}>테스트1</Link></MenuLink>
        <MenuLink><Link to='/testbet' className={currentLocation.pathname === '/testbet' ? styles.active : styles.menulink}>테스트2</Link></MenuLink>
      </MenuLeft>
      <MenuRight>
        <MenuLink><Link to='/signin' className={currentLocation.pathname === '/signin' ? styles.active : styles.menulink}>로그인</Link></MenuLink>
        <MenuLink><Link to='/signup' className={currentLocation.pathname === '/signup' ? styles.active : styles.menulink}>회원가입</Link></MenuLink>
      </MenuRight>
    </Base>
  )
}

const Base = styled.div`
  display: flex;
  flex-direction: row;
  justify-content: flex-start;
  min-height: 5vh;
  align-items: center;
  width: 100%;
  height: 100%;
  margin-left: auto;
  padding: 0 20px;
  box-sizing: border-box;
  background-color: #282c34;
  color: white;
`
const MenuLeft = styled.div`
  display: flex;
  flex-direction: row;
  justify-content: flex-start;
  align-items: center;
  width: 100%;
  height: 100%;
  color: white;
`
const MenuRight = styled.div`
  display: flex;
  flex-direction: row;
  justify-content: flex-end;
  align-items: center;
  width: 100%;
  height: 100%;
  color: white;
`
const HomeLink = styled.div`
  display: flex;
  flex-direction: row;
  align-items: center;
  height: 100%;
  padding: 0 10px;
  box-sizing: border-box;
  cursor: pointer;

  font-size: 1.5rem;
  font-weight: bold;
  
  text-align: left;
  margin-top: -3px;
  color: #3fa0b3;
  cursor: pointer;
`
const MenuLink = styled.div`
  display: flex;
  flex-direction: row;
  align-items: center;
  height: 100%;
  padding: 0 10px;
  box-sizing: border-box;
  cursor: pointer;
  
  font-size: 1.0rem;

  text-align: left;
  padding: 0 10px;
  color: white;
  text-decoration: none;
  cursor: pointer;
  &:hover {
    color: #3fa0b3;
  }
  &.active {
    color: #3fa0b3;
  }
`
