import React, { useState } from 'react';
import { Outlet, useLocation } from 'react-router-dom';
import styled from 'styled-components';

const TestBet = () => {
  const [initialBalance, setInitialBalance] = useState(3000000);
  const [initialValue, setInitialValue] = useState(1000);
  const [betArray, setBetArray] = useState([initialValue, initialValue, initialValue, initialValue]);
  const [multiplierB, setMultiplierB] = useState(1.95);
  const [multiplierP, setMultiplierP] = useState(2.0);
  const [countBet, setCountBet] = useState(0);
  const [betAmount, setBetAmount] = useState(initialValue * 2);
  const [balance, setBalance] = useState(initialBalance);
  const [profit, setProfit] = useState(0);
  const [logs, setLogs] = useState([]);
  const [currentTarget, setCurrentTarget] = useState('뱅커'); // ['B', 'P']

  const handleInitialBalanceChange = (e) => {
    const value = parseInt(e.target.value, 10); // 10진수로 변환
    setInitialBalance(value);
  };

  const handleInitialValueChange = (e) => {
    const value = parseInt(e.target.value, 10);
    setInitialBalance(initialBalance);
    setInitialValue(value);
    setBetArray([value, value, value, value]);
    setBetAmount(value * 2);
    setBalance(initialBalance);
    setProfit(0);
    setLogs([]);
    setCountBet(0);
    setCurrentTarget('뱅커');
  };

  const handleMultiplierChangeB = (e) => {
    setMultiplierB(parseFloat(e.target.value));
  };

  const handleMultiplierChangeP = (e) => {
    setMultiplierP(parseFloat(e.target.value));
  };

  const initBet = () => {
    setBetArray([initialValue, initialValue, initialValue, initialValue]);
    setBetAmount(initialValue * 2);
    setBalance(initialBalance);
    setProfit(0);
    setLogs([]);
    setCountBet(0);
    setCurrentTarget('뱅커');
  };

  const reverseBtn = () => {
    currentTarget === '뱅커' ? setCurrentTarget('플레이어') : setCurrentTarget('뱅커');
  };
  
  const writeLog = (newLog) => {
    setLogs((prevLogs) => {
      const newLogs = [...prevLogs, newLog];
      if (newLogs.length > 30) {
        return newLogs.slice(1);
      }
      return newLogs;
    });
  };


  const placeBet = (betOn) => {
    currentTarget === '뱅커' ? setCurrentTarget('플레이어') : setCurrentTarget('뱅커');
    const myBet = currentTarget === '뱅커' ? 'B' : 'P';
    let newProfit = profit - betAmount;
    let newBalance = balance - betAmount;
    const result = myBet === betOn ? 'O' : 'X';

    let newBetArray = [...betArray];

    if (myBet === betOn) {
      if (myBet === 'P') {
        newProfit += betAmount * multiplierP;
        newBalance += betAmount * multiplierP;
      } else {
        newProfit += betAmount * multiplierB;
        newBalance += betAmount * multiplierB;
      }
      newBetArray.shift(); // remove first element
      newBetArray.pop();   // remove last element
    } else {
      newBetArray.push(betAmount); // add new element
    }

    const log = `[${countBet}] : ${myBet}(${betAmount}) => ${betOn}(${betAmount})${result}(${newProfit})`;
    //setLogs((prevLogs) => [...prevLogs, log]);
    writeLog(log);
    

    let newBetAmount;
    if (newBetArray.length === 0) {
      newBetArray = [initialValue, initialValue, initialValue, initialValue];
      newBetAmount = initialValue * 2;
      //setLogs((prevLogs) => [...prevLogs, '----------------------------------------']);
      writeLog('----------------------------------------');
      // Reset logs when a new set starts
      //setTimeout(() => setLogs([]), 1000); // Clear logs after a short delay to allow separator to be displayed
      // 즉시 초기화
      //setLogs([]);
    } else if (newBetArray.length === 1) {
      newBetAmount = newBetArray[0];
    } else {
      newBetAmount = newBetArray[0] + newBetArray[newBetArray.length - 1];
    }

    setBetArray(newBetArray);
    setBetAmount(newBetAmount);
    setProfit(newProfit);
    setBalance(newBalance);
    setCountBet(countBet + 1);
  };

  return (
    <Base>
      <h1>Betting Game</h1>
      <div>
        <label>
          초기 잔고:
          <input type="number" value={initialBalance} onChange={handleInitialBalanceChange} />
        </label>
      </div>
      <div>
        <label>
          베팅 기준 금액:
          <input type="number" value={initialValue} onChange={handleInitialValueChange} />
        </label>
      </div>
      <div>
        <label>
          뱅커 배당률:
          <input type="number" step="0.01" value={multiplierB.toFixed(2)} onChange={handleMultiplierChangeB} />
        </label>
      </div>
      <div>
        <label>
        플레이어 배당률:
          <input type="number" step="0.01" value={multiplierP.toFixed(2)} onChange={handleMultiplierChangeP} />
        </label>
      </div>
      <div>
        <h2>Summary</h2>
        <p>잔고: 
        <span style={{ backgroundColor: 'pink', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
          {balance}
        </span>
          , 수익금: 
          <span style={{ backgroundColor: 'pink', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
          {profit}
          </span>
           <button onClick={() => initBet()}>초기화</button> 총 베팅 횟수: {countBet}</p>
        <p>배팅 배열: 
          {betArray.map((bet, index) => (
            <span 
              key={index} 
              style={{ 
                backgroundColor: index === 0 || index === betArray.length - 1 ? 'yellow' : 'transparent', 
                padding: '2px 5px',
                margin: '0 5px',
                borderRadius: '4px',
                color: index === 0 || index === betArray.length - 1 ? 'black' : 'white'
              }}
            >
              {bet}
            </span>
          ))}
        </p>
      </div>
      <div>
        <span style={{ backgroundColor: 'lightblue', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
          {currentTarget}
        </span> 에 
        <span style={{ backgroundColor: 'lightgreen', padding: '2px 5px', borderRadius: '4px', color: 'black' }}>
          {betAmount}
        </span> 을 베팅하세요.
        <button onClick={() => reverseBtn()}>뒤집기</button><br/>
        
        <br/>게임의 결과:
        <button onClick={() => placeBet('B')}>뱅커 승리</button>
        <button onClick={() => placeBet('P')}>플레이어 승리</button>
      </div>
      <div>
        <h2>Logs</h2>
        <ul>
          {logs.map((log, index) => (
            <li key={index}>{log}</li>
          ))}
        </ul>
      </div>
      <Outlet />
    </Base>
  );
};

export default TestBet;

const Base = styled.div`
  position: fixed;
  top: 5.0vh;
  min-height: 91.6vh;
  left: 0;
  width: 100%;
  background-color: rgba(0, 0, 0, 0.7);
  color: #fff;
  padding: 0;
  text-align: left; /* 좌측 정렬 */
`;

const MenuLeft = styled.div`
	font-size: 100%;
  align-items: center;
  color: white;
`;
